        "targetId": "c-mo3txast-25e97f863d2c",
        "linkType": "related",
        "createdAt": "2026-04-18T04:21:33.380Z"
      }
    ],
    "inbound": []
  },
  "parent": {
    "id": "c-mo3o0euk-054bbde3ae5f",
    "goal": "Scope the MVP Patron Anima — what's in the first prototype, what's deferred, and what design questions do we need to answer before commissioning it?",
    "status": "live"
  },
